import React from 'react';

function VideoCard({ url }) {
  return (
    <div className="videoCardPlayer">
      <iframe id="ytplayer" type="text/html" width="720" height="405"
        src={url}
        frameborder="0" allowfullscreen>
      </iframe>
    </div>
  );
}

export default VideoCard;
